/**
 * Workspace & Team Management Engine
 *
 * Pure functions for workspace RBAC, member management,
 * invitations, and permission checking.
 */

// ─── Types ───────────────────────────────────────────────────────────

export type WorkspaceRole = 'owner' | 'admin' | 'editor' | 'viewer';

export type WorkspacePlan = 'free' | 'pro' | 'business';

export type MemberStatus = 'active' | 'invited' | 'suspended';

export type InvitationStatus = 'pending' | 'accepted' | 'expired' | 'revoked';

export type WorkspaceAction =
  | 'view_project'
  | 'edit_project'
  | 'delete_project'
  | 'invite_member'
  | 'remove_member'
  | 'change_role'
  | 'edit_workspace'
  | 'delete_workspace'
  | 'manage_billing';

export interface Workspace {
  id: string;
  name: string;
  slug: string;
  description: string;
  ownerId: string;
  avatarUrl?: string;
  plan: WorkspacePlan;
  maxMembers: number;
  maxProjects: number;
  createdAt: string;
  updatedAt: string;
}

export interface WorkspaceMember {
  id: string;
  workspaceId: string;
  userId: string;
  email: string;
  name: string;
  avatarUrl?: string;
  role: WorkspaceRole;
  joinedAt: string;
  invitedBy: string;
  status: MemberStatus;
}

export interface WorkspaceInvitation {
  id: string;
  workspaceId: string;
  email: string;
  role: WorkspaceRole;
  invitedBy: string;
  expiresAt: string;
  token: string;
  status: InvitationStatus;
  createdAt: string;
}

export interface WorkspaceProject {
  projectId: string;
  workspaceId: string;
  addedBy: string;
  addedAt: string;
}

export interface PermissionSet {
  canViewProjects: boolean;
  canEditProjects: boolean;
  canDeleteProjects: boolean;
  canInviteMembers: boolean;
  canRemoveMembers: boolean;
  canChangeRoles: boolean;
  canEditWorkspace: boolean;
  canDeleteWorkspace: boolean;
  canManageBilling: boolean;
}

