// ─── Plan Limits ─────────────────────────────────────────────────────

export const PLAN_LIMITS: Record<WorkspacePlan, { maxMembers: number; maxProjects: number }> = {
  free: { maxMembers: 3, maxProjects: 5 },
  pro: { maxMembers: 10, maxProjects: 50 },
  business: { maxMembers: 50, maxProjects: 9999 },
};

// ─── Action → Permission Mapping ────────────────────────────────────

const ACTION_PERMISSION_MAP: Record<WorkspaceAction, keyof PermissionSet> = {
  view_project: 'canViewProjects',
  edit_project: 'canEditProjects',
  delete_project: 'canDeleteProjects',
  invite_member: 'canInviteMembers',
  remove_member: 'canRemoveMembers',
  change_role: 'canChangeRoles',
  edit_workspace: 'canEditWorkspace',
  delete_workspace: 'canDeleteWorkspace',
  manage_billing: 'canManageBilling',
};

// ─── Role Hierarchy ──────────────────────────────────────────────────

const ROLE_HIERARCHY: Record<WorkspaceRole, number> = {
  owner: 4,
  admin: 3,
  editor: 2,
  viewer: 1,
};

// ─── Permission Functions ────────────────────────────────────────────

/**
 * Returns the full permission set for a given role.
 */
export function getPermissions(role: WorkspaceRole): PermissionSet {
  return { ...ROLE_PERMISSIONS[role] };
}

/**
 * Checks if a role has a specific permission.
 */
export function hasPermission(role: WorkspaceRole, permission: keyof PermissionSet): boolean {
  return ROLE_PERMISSIONS[role][permission];
}

/**
 * Checks if a role can perform a specific workspace action.
 */
export function canPerformAction(actorRole: WorkspaceRole, action: WorkspaceAction): boolean {
  const permissionKey = ACTION_PERMISSION_MAP[action];
  return ROLE_PERMISSIONS[actorRole][permissionKey];
}

/**
 * Determines if an actor can change another member's role.
 *
 * Rules:
 * - Only owner can promote to admin
 * - Admin cannot demote/change another admin
 * - Viewer/editor cannot change any roles
 * - Cannot change own role (owner→owner)
 * - Actor must have higher hierarchy than target current role
 * - Actor must have higher hierarchy than target new role (except owner promoting to admin)
 */
export function canChangeRole(
  actorRole: WorkspaceRole,
  targetCurrentRole: WorkspaceRole,
  targetNewRole: WorkspaceRole,
): boolean {
  // Only owner and admin can change roles
  if (!hasPermission(actorRole, 'canChangeRoles')) {
    return false;
  }

  // Cannot change to the same role
  if (targetCurrentRole === targetNewRole) {
    return false;
  }

  // Cannot promote to owner
  if (targetNewRole === 'owner') {
    return false;
  }

  // Only owner can promote to admin
  if (targetNewRole === 'admin' && actorRole !== 'owner') {
    return false;
  }

  // Admin cannot change another admin's role
  if (actorRole === 'admin' && targetCurrentRole === 'admin') {
    return false;
  }

  // Admin cannot change owner's role
  if (targetCurrentRole === 'owner') {
    return false;
  }

  // Actor must have higher hierarchy than target's current role (unless owner)
  if (actorRole !== 'owner' && ROLE_HIERARCHY[actorRole] <= ROLE_HIERARCHY[targetCurrentRole]) {
    return false;
  }

  return true;
}

// ─── Validation Functions ────────────────────────────────────────────

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const SLUG_REGEX = /^[a-z0-9][a-z0-9-]*[a-z0-9]$/;

/**
 * Validates workspace data, returning an array of error messages.
 * Empty array means valid.
 */
export function validateWorkspace(workspace: Partial<Workspace>): string[] {
  const errors: string[] = [];

  if (!workspace.name || workspace.name.trim().length < 2) {
    errors.push('Nome deve ter pelo menos 2 caracteres');
  }
  if (workspace.name && workspace.name.trim().length > 50) {
    errors.push('Nome deve ter no máximo 50 caracteres');
  }

  if (!workspace.slug || workspace.slug.length < 3) {
    errors.push('Slug deve ter pelo menos 3 caracteres');
  }
  if (workspace.slug && workspace.slug.length > 30) {
    errors.push('Slug deve ter no máximo 30 caracteres');
  }
  if (workspace.slug && workspace.slug.length >= 3 && !SLUG_REGEX.test(workspace.slug)) {
    errors.push('Slug deve conter apenas letras minúsculas, números e hífens');
  }

  if (workspace.description && workspace.description.length > 200) {
    errors.push('Descrição deve ter no máximo 200 caracteres');
  }

  return errors;
}

/**
 * Validates an invitation against workspace constraints.
 */
export function validateInvitation(
  invitation: Partial<WorkspaceInvitation>,
  workspace: Workspace,
  currentMembers: WorkspaceMember[],
): string[] {
  const errors: string[] = [];

  if (!invitation.email || !EMAIL_REGEX.test(invitation.email)) {
    errors.push('Email inválido');
  }

  const validRoles: WorkspaceRole[] = ['owner', 'admin', 'editor', 'viewer'];
  if (!invitation.role || !validRoles.includes(invitation.role)) {
    errors.push('Role inválida');
  }

  if (invitation.email) {
    const alreadyMember = currentMembers.some(
      (m) => m.email.toLowerCase() === invitation.email!.toLowerCase(),
    );
    if (alreadyMember) {
      errors.push('Usuário já é membro deste workspace');
    }
  }

  if (invitation.invitedBy && invitation.email) {
    const inviter = currentMembers.find((m) => m.userId === invitation.invitedBy);
    if (inviter && inviter.email.toLowerCase() === invitation.email.toLowerCase()) {
      errors.push('Não é possível convidar a si mesmo');
    }
  }

  const activeCount = currentMembers.filter((m) => m.status !== 'suspended').length;
  if (isAtMemberLimit(workspace, activeCount)) {
    errors.push(`Limite de ${workspace.maxMembers} membros atingido para o plano ${workspace.plan}`);
  }

  return errors;
}

// ─── Utility Functions ───────────────────────────────────────────────

/**
 * Generates a URL-friendly slug from a name.
 */
export function generateSlug(name: string): string {
  return name
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 30);
}

/**
 * Checks if an invitation has expired.
 */
export function isInvitationExpired(invitation: WorkspaceInvitation): boolean {
  const expiresAt = new Date(invitation.expiresAt);
  return expiresAt.getTime() <= Date.now();
}

/**
 * Filters members by a specific role.
 */
export function getMembersByRole(
  members: WorkspaceMember[],
  role: WorkspaceRole,
): WorkspaceMember[] {
  return members.filter((m) => m.role === role);
}

/**
 * Returns only active members (excludes invited and suspended).
 */
export function getActiveMembers(members: WorkspaceMember[]): WorkspaceMember[] {
  return members.filter((m) => m.status === 'active');
}

/**
 * Checks if workspace is at its member limit.
 */
export function isAtMemberLimit(workspace: Workspace, currentMemberCount: number): boolean {
  return currentMemberCount >= workspace.maxMembers;
}

/**
 * Checks if workspace is at its project limit.
 */
export function isAtProjectLimit(workspace: Workspace, currentProjectCount: number): boolean {
  return currentProjectCount >= workspace.maxProjects;
}

/**
 * Formats a join date into a relative PT-BR string.
 */
export function formatMemberSince(joinedAt: string): string {
  const joined = new Date(joinedAt);
  const now = new Date();
  const diffMs = now.getTime() - joined.getTime();
  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

  if (diffDays < 0) {
    return 'hoje';
  }
  if (diffDays === 0) {
    return 'hoje';
  }
  if (diffDays === 1) {
    return 'há 1 dia';
  }
  if (diffDays < 30) {
    return `há ${diffDays} dias`;
  }
  const diffMonths = Math.floor(diffDays / 30);
  if (diffMonths === 1) {
    return 'há 1 mês';
  }
  if (diffMonths < 12) {
    return `há ${diffMonths} meses`;
  }
  const diffYears = Math.floor(diffMonths / 12);
  if (diffYears === 1) {
    return 'há 1 ano';
  }
  return `há ${diffYears} anos`;
}

/**
 * Returns the PT-BR label for a workspace role.
 */
export function getRoleLabel(role: WorkspaceRole): string {
  const labels: Record<WorkspaceRole, string> = {
    owner: 'Proprietário',
    admin: 'Administrador',
    editor: 'Editor',
    viewer: 'Visualizador',
  };
  return labels[role];
}

/**
 * Returns Tailwind CSS badge color classes for a workspace role.
 */
export function getRoleBadgeColor(role: WorkspaceRole): string {
  const colors: Record<WorkspaceRole, string> = {
    owner: 'bg-amber-100 text-amber-800 border-amber-300',
    admin: 'bg-purple-100 text-purple-800 border-purple-300',
    editor: 'bg-blue-100 text-blue-800 border-blue-300',
    viewer: 'bg-gray-100 text-gray-800 border-gray-300',
  };
  return colors[role];
}
